local function DYCGem(inst) local prefab = inst.prefab local repairer = inst.components.repairer if not repairer then inst:AddComponent( "repairer" ) repairer = inst.components.repairer end repairer.userepairvalue = prefab == "orangegem" and 0x3e or prefab == "yellowgem" and 0x3a or prefab == "greengem" and 0x3c or prefab == "purplegem" and 0x41 or prefab == "bluegem" and 0x37 or prefab == "redgem" and 0x37 or 0x1e end return DYCGem 